export interface PopularPlace {
  name: string
  description: string
  // Longer detail-panel-only prose. Do not use for cards/promotional surfaces.
  panelSummary?: string
  // Optional richer detail — populated per-place as we roll it out.
  coords?: { lat: number; lng: number }
  temperatures?: { month: string; high: number; low: number }[]
  precipitation?: number[]
  photos?: string[]
  bestWeatherMonths?: string
  goodWeatherMonths?: string
}

export interface CountryData {
  name: string
  code: string
  flagEmoji: string
  flagColors: [string, string, string]
  continent: string
  capital: string
  population: string
  languages: string[]
  currency: string
  government: string
  temperatures: { month: string; high: number; low: number }[]
  precipitation: number[]
  bestTimeToVisit: string
  bestVisitMonths?: number[]
  popularPlaces: PopularPlace[]
  attractions: {
    name: string
    description: string
    entityId?: string
    wikidataId?: string
    imageUrl?: string
    imagePageUrl?: string
    imageCreator?: string
    imageLicense?: string
    imageLicenseUrl?: string
    imageAttribution?: string
    imageMatchStatus?: string
    annualVisitors?: number
    annualVisitorsYear?: number
    annualVisitorsSourceUrl?: string
    bestWeatherMonths?: string
    goodWeatherMonths?: string
  }[]
  famousMovies: { title: string; year: number; description: string }[]
  popularMusic: { name: string; genre: string }[]
  celebrities: { name: string; field: string }[]
  notableFacts: string[]
  popularSouvenirs: { name: string; description: string }[]
  flightTimeFromEWR: string
  summary?: string
}


